const r = msg.record;
const envelope = {
    ingest_timestamp: msg.ingest_timestamp,
    source_topic: msg.source_topic,
    kafka_partition: 0,
    kafka_offset: 0,
    kafka_key: msg.filename,
    raw_payload: JSON.stringify(r)
};
return {
    filename: msg.filename,
    routing_topic: env.get('INGEST_DEFAULT_TOPIC') || 'sftp.ingest.raw',
    envelope: envelope
};
